mapper.select:
SELECT p.id, p.plan_name AS planName, p.plan_category AS planCategory, p.inspection_frequency AS inspectionFrequency, p.valid_start_date AS validStartDate, p.valid_end_date AS validEndDate, p.status, c.construction_name AS constructionName, c.address, a.area_name AS areaName, o.organization_name AS organizationName FROM tpc_inspection_plan p LEFT JOIN tpc_construction c ON p.construction_id = c.id LEFT JOIN tbl_organization o ON p.org_id = o.id LEFT JOIN tbl_area_node a ON c.area_code = a.code
AND p.plan_name LIKE CONCAT('%', #{request.planName}, '%')
AND p.plan_category = #{request.planCategory}
AND p.status = #{request.status}
AND p.valid_start_date >= #{request.validStartDate}
AND p.valid_end_date <= #{request.validEndDate}
AND c.construction_name LIKE CONCAT('%', #{request.constructionName}, '%')
AND o.organization_name LIKE CONCAT('%', #{request.organizationName}, '%')
AND a.area_name LIKE CONCAT('%', #{request.areaName}, '%')
/*ORDER BY p.create_time DESC*/
